$ErrorActionPreference = 'Stop'

Add-Type -AssemblyName System.IO.Compression.FileSystem

$DocxPath = Join-Path $PSScriptRoot 'Текст магистерской.docx'
$BackupPath = Join-Path $PSScriptRoot ('Текст магистерской.before_structured_rewrite_' + (Get-Date -Format 'yyyyMMdd_HHmmss') + '.docx')

if (-not (Test-Path -LiteralPath $DocxPath)) {
    throw "DOCX file not found: $DocxPath"
}

Copy-Item -LiteralPath $DocxPath -Destination $BackupPath

function XmlEscape {
    param([string]$Text)
    if ($null -eq $Text) { return '' }
    return [System.Security.SecurityElement]::Escape($Text)
}

function New-RunXml {
    param(
        [string]$Text,
        [bool]$Bold = $false,
        [bool]$Italic = $false,
        [int]$Size = 28
    )
    $rPr = '<w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="' + $Size + '"/>'
    if ($Bold) { $rPr += '<w:b/>' }
    if ($Italic) { $rPr += '<w:i/>' }
    $rPr += '</w:rPr>'
    return '<w:r>' + $rPr + '<w:t xml:space="preserve">' + (XmlEscape $Text) + '</w:t></w:r>'
}

function New-ParagraphXml {
    param(
        [string]$Text,
        [string]$Style = 'a1',
        [string]$Justification = 'both',
        [bool]$Bold = $false,
        [bool]$Italic = $false,
        [int]$Size = 28
    )
    $pPr = '<w:pPr>'
    if ($Style) { $pPr += '<w:pStyle w:val="' + $Style + '"/>' }
    if ($Justification) { $pPr += '<w:jc w:val="' + $Justification + '"/>' }
    $pPr += '</w:pPr>'
    return '<w:p>' + $pPr + (New-RunXml -Text $Text -Bold $Bold -Italic $Italic -Size $Size) + '</w:p>'
}

function New-CellXml {
    param([string]$Text, [bool]$Bold = $false)
    return '<w:tc><w:tcPr><w:tcW w:w="3000" w:type="dxa"/></w:tcPr>' + (New-ParagraphXml -Text $Text -Style 'a1' -Justification 'left' -Bold $Bold -Size 24) + '</w:tc>'
}

function New-TableXml {
    param(
        [string]$Title,
        [string[]]$Headers,
        [object[]]$Rows
    )
    $xml = ''
    if ($Title) {
        $xml += New-ParagraphXml -Text $Title -Style 'a1' -Justification 'center' -Bold $true
    }
    $xml += '<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/><w:tblBorders><w:top w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:left w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:bottom w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:right w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:insideH w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:insideV w:val="single" w:sz="4" w:space="0" w:color="auto"/></w:tblBorders></w:tblPr>'
    $xml += '<w:tr>'
    foreach ($h in $Headers) { $xml += New-CellXml -Text $h -Bold $true }
    $xml += '</w:tr>'
    foreach ($row in $Rows) {
        $xml += '<w:tr>'
        foreach ($cell in $row) { $xml += New-CellXml -Text ([string]$cell) -Bold $false }
        $xml += '</w:tr>'
    }
    $xml += '</w:tbl>'
    return $xml
}

$parts = New-Object System.Collections.Generic.List[string]

function Add-P { param([string]$Text) $script:parts.Add((New-ParagraphXml -Text $Text -Style 'a1' -Justification 'both')) }
function Add-C { param([string]$Text) $script:parts.Add((New-ParagraphXml -Text $Text -Style 'a1' -Justification 'center')) }
function Add-Title { param([string]$Text) $script:parts.Add((New-ParagraphXml -Text $Text -Style 'aa' -Justification 'center' -Bold $true -Size 32)) }
function Add-H1 { param([string]$Text) $script:parts.Add((New-ParagraphXml -Text $Text -Style '1' -Justification 'center' -Bold $true)) }
function Add-H2 { param([string]$Text) $script:parts.Add((New-ParagraphXml -Text $Text -Style '21' -Justification 'left' -Bold $true)) }
function Add-H3 { param([string]$Text) $script:parts.Add((New-ParagraphXml -Text $Text -Style '31' -Justification 'left' -Bold $true)) }
function Add-Note { param([string]$Text) $script:parts.Add((New-ParagraphXml -Text ('Примечание для доработки: ' + $Text) -Style 'af8' -Justification 'both' -Italic $true -Size 24)) }
function Add-Table { param([string]$Title, [string[]]$Headers, [object[]]$Rows) $script:parts.Add((New-TableXml -Title $Title -Headers $Headers -Rows $Rows)) }

