    @('Управление лимитом', 'Повышение, снижение или сохранение лимита', 'Доходность и риск', 'Оценить изменение результата, а не только текущий риск'),
    @('Мягкое взыскание', 'Канал и интенсивность контакта', 'Погашение задолженности', 'Снизить давление на клиента и стоимость работы'),
    @('Предотвращение фрода', 'Дополнительная проверка или блокировка', 'Предотвращенная потеря', 'Применять осторожно, когда контроль этически допустим')
