    @('Рисунок 2.1', 'Потенциальные исходы и каналы коммуникации', 'Методическая схема'),
    @('Рисунок 3.1', 'Генерация синтетического причинного слоя', 'prepare_dataset.ipynb'),
    @('Рисунок 3.2', 'Propensity overlap contacted/control', 'docs/tier1_outputs/fig_propensity_overlap.png'),
