$zip = [System.IO.Compression.ZipFile]::OpenRead($DocxPath)
try {
    $entry = $zip.GetEntry('word/document.xml')
    $stream = $entry.Open()
    try {
        $reader = New-Object System.IO.StreamReader($stream)
        $oldXml = $reader.ReadToEnd()
        $reader.Dispose()
    } finally {
        $stream.Dispose()
    }
} finally {
    $zip.Dispose()
}

$sectPrMatch = [regex]::Match($oldXml, '<w:sectPr[\s\S]*?</w:sectPr>')
if (-not $sectPrMatch.Success) {
    throw 'Could not find section properties in document.xml'
}

$newBody = ($parts -join "`n") + "`n" + $sectPrMatch.Value
$newXml = [regex]::Replace($oldXml, '<w:body>[\s\S]*?</w:body>', '<w:body>' + $newBody + '</w:body>')

$tmpXml = Join-Path ([System.IO.Path]::GetTempPath()) ('document_' + [guid]::NewGuid().ToString('N') + '.xml')
[System.IO.File]::WriteAllText($tmpXml, $newXml, (New-Object System.Text.UTF8Encoding($false)))

$zip = [System.IO.Compression.ZipFile]::Open($DocxPath, [System.IO.Compression.ZipArchiveMode]::Update)
try {
    $entry = $zip.GetEntry('word/document.xml')
    if ($entry) { $entry.Delete() }
    $newEntry = $zip.CreateEntry('word/document.xml')
    $entryStream = $newEntry.Open()
    try {
        $fileStream = [System.IO.File]::OpenRead($tmpXml)
        try {
            $fileStream.CopyTo($entryStream)
        } finally {
            $fileStream.Dispose()
        }
    } finally {
        $entryStream.Dispose()
    }
} finally {
    $zip.Dispose()
}

Remove-Item -LiteralPath $tmpXml -Force

Write-Host "Rewritten: $DocxPath"
Write-Host "Backup: $BackupPath"
Write-Host "Blocks written: $($parts.Count)"
